/** AfuChat brand logo rendered from SVG — use instead of <Image source={afuSymbol}> */
export function AfuLogo({
  size = 72,
  style,
}: {
  size?: number;
  style?: StyleProp<ViewStyle>;
}) {
  return (
    <SvgXml xml={SVG_XML} width={size} height={size} style={style} />
  );
}

export default AfuLogo;
